const { Client } = require('pg');
(async () => {
  const client = new Client({ connectionString: process.env.DATABASE_PUBLIC_URL, connectionTimeoutMillis: 10000, ssl: { rejectUnauthorized: false } });
  await client.connect();
  try {
    const result = await client.query(`
      with repo as (
        select id, policy::jsonb as policy, graph::jsonb as graph, visibility_events::jsonb as events
        from scope_repositories
        where id = 'adamblumoff/scope-vcs'
      ), commits as (
        select ordinality as seq,
               commit->>'id' as id,
               commit->>'message' as message,
               commit->>'author_id' as author_id,
               jsonb_array_length(commit->'changes') as change_count,
               coalesce((select jsonb_agg(jsonb_build_object(
                 'path', ch->'path'->>'raw',
                 'visibility', ch->>'visibility',
                 'has_new_content', ch ? 'new_content' and ch->'new_content' is not null
               ) order by ch_ord)
               from jsonb_array_elements(commit->'changes') with ordinality as c(ch, ch_ord)), '[]'::jsonb) as changes
        from repo, jsonb_array_elements(graph->'commits') with ordinality as g(commit, ordinality)
      ), events as (
        select ordinality as seq,
               event->>'id' as id,
               event->>'after_commit_id' as after_commit_id,
               event->>'source_commit_id' as source_commit_id,
               event->'path'->>'raw' as path,
               event->>'old_visibility' as old_visibility,
               event->>'new_visibility' as new_visibility,
               event ? 'current_content' and event->'current_content' is not null as has_current_content
        from repo, jsonb_array_elements(events) with ordinality as e(event, ordinality)
      )
      select jsonb_build_object(
        'commits', (select jsonb_agg(to_jsonb(commits) order by seq) from commits),
        'events', (select jsonb_agg(to_jsonb(events) order by seq) from events),
        'event_counts_by_transition', (select jsonb_object_agg(transition, count) from (select old_visibility || '->' || new_visibility as transition, count(*) from events group by 1 order by 1) t),
        'event_counts_by_after_commit', (select jsonb_object_agg(coalesce(after_commit_id, '<none>'), count) from (select after_commit_id, count(*) from events group by 1 order by 1) t),
        'event_counts_by_source_commit', (select jsonb_object_agg(coalesce(source_commit_id, '<none>'), count) from (select source_commit_id, count(*) from events group by 1 order by 1) t)
      ) as data
    `);
    console.log(JSON.stringify(result.rows[0].data, null, 2));
  } finally {
    await client.end();
  }
})().catch((error) => { console.error(error.stack || error.message); process.exit(1); });
