const { Client } = require('pg');
function canRead(policy, path) {
  const rule = policy.rules.find((rule) => rule.path === path);
  return (rule?.visibility ?? policy.default_visibility) === 'Public';
}
function effectiveVisibility(policy, path) {
  return policy.rules.find((rule) => rule.path === path)?.visibility ?? policy.default_visibility;
}
function visibilityReadableForEvent(policy, path, visibility) {
  if (visibility === 'Public') return true;
  return effectiveVisibility(policy, path) === 'Private' && canRead(policy, path);
}
function project(policy, graph, events) {
  const commits = [];
  let lastVisible = null;
  const principal = 'public';
  const commitPositions = new Map(graph.commits.map((commit, index) => [commit.id, index]));
  const starts = new Map();
  for (const event of events) {
    if (!canRead(policy, event.path)) continue;
    const oldReadable = visibilityReadableForEvent(policy, event.path, event.old_visibility);
    const newReadable = visibilityReadableForEvent(policy, event.path, event.new_visibility);
    if (oldReadable || !newReadable) continue;
    let sourceCommitIndex = undefined;
    if (event.source_commit_id && commitPositions.has(event.source_commit_id)) sourceCommitIndex = commitPositions.get(event.source_commit_id);
    else if (event.after_commit_id && commitPositions.has(event.after_commit_id)) sourceCommitIndex = commitPositions.get(event.after_commit_id) + 1;
    else sourceCommitIndex = 0;
    starts.set(event.path, { sourceCommitIndex, baselineEventId: event.source_commit_id == null ? event.id : null });
  }
  const baselinesBefore = [];
  const baselinesAfter = new Map();
  for (const event of events) {
    const start = starts.get(event.path);
    if (start?.baselineEventId !== event.id) continue;
    if (!canRead(policy, event.path)) continue;
    if (!event.current_content) continue;
    if (event.after_commit_id) {
      if (!baselinesAfter.has(event.after_commit_id)) baselinesAfter.set(event.after_commit_id, []);
      baselinesAfter.get(event.after_commit_id).push(event);
    } else {
      baselinesBefore.push(event);
    }
  }
  function addBaselines(afterCommitId) {
    const list = afterCommitId == null ? baselinesBefore : baselinesAfter.get(afterCommitId) || [];
    for (const event of list) {
      const projectedId = `pv_${principal}_${event.id}_${commits.length + 1}`;
      commits.push({
        projected_id: projectedId,
        logical_commit_id: event.id,
        parent_projected_id: lastVisible,
        author: null,
        message: 'Projection baseline',
        changes: [{ path: event.path, new_content: event.current_content }],
        source: 'baseline',
      });
      lastVisible = projectedId;
    }
  }
  addBaselines(null);
  graph.commits.forEach((logical, commitIndex) => {
    const visibleChanges = logical.changes.filter((change) => {
      const readable = change.visibility === 'Public' && canRead(policy, change.path);
      const start = starts.get(change.path);
      const inEpoch = start?.sourceCommitIndex == null || commitIndex >= start.sourceCommitIndex;
      return readable && inEpoch;
    }).map((change) => ({ path: change.path, new_content: change.new_content }));
    if (visibleChanges.length > 0) {
      const projectedId = `pv_${principal}_${logical.id}_${commits.length + 1}`;
      const partial = visibleChanges.length < logical.changes.length;
      commits.push({
        projected_id: projectedId,
        logical_commit_id: logical.id,
        parent_projected_id: lastVisible,
        author: partial ? null : logical.author_id,
        message: partial ? 'Projected public update' : logical.message,
        changes: visibleChanges,
        source: 'logical',
      });
      lastVisible = projectedId;
    }
    addBaselines(logical.id);
  });
  return { starts, commits };
}
(async () => {
  const client = new Client({ connectionString: process.env.DATABASE_PUBLIC_URL, connectionTimeoutMillis: 10000, ssl: { rejectUnauthorized: false } });
  await client.connect();
  try {
    const result = await client.query(`select policy::jsonb as policy, graph::jsonb as graph, visibility_events::jsonb as events from scope_repositories where id = 'adamblumoff/scope-vcs'`);
    const { policy, graph, events } = result.rows[0];
    const projected = project(policy, graph, events);
    const rows = projected.commits.map((commit, index) => ({
      n: index + 1,
      source: commit.source,
      message: commit.message,
      logical_commit_id: commit.logical_commit_id,
      parent: commit.parent_projected_id,
      change_count: commit.changes.length,
      paths: commit.changes.map((c) => c.path),
    }));
    console.log(JSON.stringify({ projectedCommitCount: rows.length, rows }, null, 2));
  } finally {
    await client.end();
  }
})().catch((error) => { console.error(error.stack || error.message); process.exit(1); });
